css:
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: Arial, sans-serif;
    padding: 0;
    margin: 0;
    background: white;
    font-size: 12px;
}

.print-format {
    width: 210mm;
    max-width: 210mm;
    margin: 0 auto;
    background: white;
    padding: 10mm;
    box-sizing: border-box;
}

.header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    border: 2px solid #000;
    padding: 10px 12px;
    margin-bottom: 12px;
    min-height: 75px;
}

.company-logo {
    width: 45px;
    height: 45px;
    background: #f8f9fa;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 1px solid #ddd;
    flex-shrink: 0;
    margin-right: 12px;
}

.star {
    font-size: 24px;
    color: #c4d82e;
    font-weight: bold;
}

.company-info {
    flex: 1;
    text-align: center;
    padding: 0 12px;
    max-width: 65%;
}

.company-name {
    font-size: 15px;
    font-weight: bold;
    margin-bottom: 4px;
    line-height: 1.2;
}

.company-address {
    font-size: 9px;
    color: #333;
    line-height: 1.3;
    margin-bottom: 3px;
}

.gst-info {
    font-size: 8px;
    color: #555;
    margin-top: 3px;
}

.header-right {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex-shrink: 0;
    gap: 6px;
}

.to-receive-label {
    background: #f0f0f0;
    padding: 4px 10px;
    text-align: center;
    font-weight: bold;
    font-size: 10px;
    border: 1px solid #ccc;
    white-space: nowrap;
}

.qr-placeholder {
    width: 45px;
    height: 45px;
    background: #000;
    border: 1px solid #333;
}

.supplier-title {
    text-align: center;
    color: #d946ef;
    font-size: 13px;
    font-weight: bold;
    margin: 10px 0 15px 0;
}

.po-details {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 15px;
    margin-bottom: 15px;
}

.detail-section {
    border: 1px solid #000;
    padding: 8px 10px;
}

.detail-row {
    display: flex;
    margin-bottom: 6px;
    font-size: 10px;
}

.detail-label {
    font-weight: bold;
    width: 100px;
    color: #333;
    flex-shrink: 0;
}

.detail-value {
    color: #d946ef;
    flex: 1;
}

.vendor-delivery {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 15px;
    margin-bottom: 15px;
}

.section-box {
    border: 1px solid #000;
    padding: 8px 10px;
    min-height: 100px;
}

.section-title {
    font-weight: bold;
    font-size: 10px;
    margin-bottom: 6px;
    color: #333;
}

.section-title.delivery {
    color: #d946ef;
}

.section-content {
    font-size: 9px;
    line-height: 1.5;
    color: #333;
}

.section-content strong {
    font-weight: bold;
}

.section-content.delivery strong {
    color: #d946ef;
}

.items-table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 15px;
    font-size: 9px;
    border: 1px solid #000;
}

.items-table th {
    background: #f5f5f5;
    border: 1px solid #000;
    padding: 6px 4px;
    text-align: center;
    font-weight: bold;
    font-size: 8px;
    vertical-align: middle;
}

.items-table td {
    border: 1px solid #000;
    padding: 6px 4px;
    vertical-align: middle;
    text-align: center;
}

.items-table td:nth-child(2) {
    text-align: left;
}

.items-table td:nth-child(7),
.items-table td:nth-child(9) {
    text-align: right;
}

.total-row {
    background: #f0f0f0 !important;
    font-weight: bold;
}

.total-row td:nth-child(1) {
    text-align: left;
}

.tax-section {
    margin-top: 10px;
    font-size: 10px;
}

.tax-header {
    text-align: right;
    font-weight: bold;
    margin-bottom: 5px;
}

.tax-row {
    display: flex;
    justify-content: flex-end;
    margin-bottom: 3px;
}

.tax-label {
    width: 120px;
    text-align: right;
    padding-right: 15px;
}

.tax-value {
    width: 80px;
    text-align: right;
    font-weight: bold;
}

.net-amount-row {
    border-top: 1px solid #000;
    padding-top: 3px;
    margin-top: 5px;
}

.amount-words {
    border: 1px solid #000;
    padding: 8px;
    margin-bottom: 12px;
    font-size: 10px;
    min-height: 30px;
}

.remarks-section,
.order-no-section {
    border: 1px solid #000;
    padding: 8px;
    margin-bottom: 12px;
    font-size: 10px;
    min-height: 40px;
}

.terms-section {
    border: 1px solid #000;
    padding: 8px;
    margin-bottom: 20px;
    min-height: 60px;
    font-size: 9px;
}

.signatures {
    display: grid;
    grid-template-columns: 1fr 1fr 1fr;
    gap: 15px;
    margin-top: 30px;
}

.signature-box {
    text-align: center;
}

.signature-line {
    border-top: 1px solid #333;
    margin-top: 40px;
    padding-top: 4px;
    font-size: 9px;
    font-weight: bold;
}

.signature-line small {
    font-size: 8px;
    display: block;
    margin-top: 2px;
}

@media print {
    body {
        background: white;
        padding: 0;
        margin: 0;
    }

    .print-format {
        padding: 5mm;
    }

    @page {
        margin: 10mm;
        size: A4;
    }
}

.items-table th:nth-child(1) { width: 5%; }
.items-table th:nth-child(2) { width: 28%; }
.items-table th:nth-child(3) { width: 12%; }
.items-table th:nth-child(4) { width: 8%; }
.items-table th:nth-child(5) { width: 8%; }
.items-table th:nth-child(6) { width: 8%; }
.items-table th:nth-child(7) { width: 12%; }
.items-table th:nth-child(8) { width: 7%; }
.items-table th:nth-child(9) { width: 12%; }
